private func retry(_ request: Request,
                       for session: Session,
                       dueTo error: any Error,
                       using retriers: [any RequestRetrier],
                       completion: @escaping @Sendable (RetryResult) -> Void) {
        var pendingRetriers = retriers

        guard !pendingRetriers.isEmpty else { completion(.doNotRetry); return }

        let retrier = pendingRetriers.removeFirst()

        retrier.retry(request, for: session, dueTo: error) { [pendingRetriers] result in
            switch result {
            case .retry, .retryWithDelay, .doNotRetryWithError:
                completion(result)
            case .doNotRetry:
                // Only continue to the next retrier if retry was not triggered and no error was encountered
                self.retry(request, for: session, dueTo: error, using: pendingRetriers, completion: completion)
            }
        }
    }

do {
    if options.contains(.removePreviousFile), fileManager.fileExists(atPath: destination.path) {
        try fileManager.removeItem(at: destination)
    }

    if options.contains(.createIntermediateDirectories) {
        let directory = destination.deletingLastPathComponent()
        try fileManager.createDirectory(at: directory, withIntermediateDirectories: true)
    }

    try fileManager.moveItem(at: location, to: destination)

    request.didFinishDownloading(using: downloadTask, with: .success(destination))
} catch {
    request.didFinishDownloading(using: downloadTask, with: .failure(.downloadedFileMoveFailed(error: error,
                                                                                               source: location,
                                                                                               destination: destination)))
}

if multipartFormData.read(\.contentLength) < encodingMemoryThreshold {
    let data = try multipartFormData.read { try $0.encode() }

    uploadable = .data(data)
} else {
    let tempDirectoryURL = fileManager.temporaryDirectory
    let directoryURL = tempDirectoryURL.appendingPathComponent("org.alamofire.manager/multipart.form.data")
    let fileName = UUID().uuidString
    let fileURL = directoryURL.appendingPathComponent(fileName)

    try fileManager.createDirectory(at: directoryURL, withIntermediateDirectories: true, attributes: nil)

    do {
        try multipartFormData.read { try $0.writeEncodedData(to: fileURL) }
    } catch {
        // Cleanup after attempted write if it fails.
        try? fileManager.removeItem(at: fileURL)
        throw error
    }

    uploadable = .file(fileURL, shouldRemove: true)
}

do {
  if let (argument, arguments) = try parseCustomCompletion(from: arguments)
  {
    let completions: [String]
    if let syncCompletions =
      try customCompleteSync(argument, forArguments: arguments)
    {
      completions = syncCompletions
    } else if case .customAsync(let complete) = argument.completion.kind {
      let (arguments, index, prefix) =
        try parseCustomCompletionArguments(from: arguments)
      completions = await complete(arguments, index, prefix)
    } else {
      throw ParserError.invalidState
    }
    try throwCompletionScriptCustomResponse(for: completions)
  }
} catch let error as ParserError {
  throw CommandError(
    commandStack: [commandTree.element],
    parserError: error
  )
} catch {
  fatalError("Internal error: \(error)")
}

do {
  try checkForCompletionScriptRequest(&split)
  try descendingParse(&split)
  let result = try extractLastParsedValue(split)

  // HelpCommand is a valid result, but needs extra information about
  // the tree from the parser to build its stack of commands.
  if var helpResult = result as? HelpCommand {
    try helpResult.buildCommandStack(with: self)
    return helpResult
  }
  return result
} catch let error as CommandError {
  throw error
} catch let error as ParserError {
  let error = arguments.isEmpty ? ParserError.noArguments(error) : error
  throw CommandError(commandStack: commandStack, parserError: error)
} catch let helpRequest as HelpRequested {
  return HelpCommand(
    commandStack: commandStack,
    visibility: helpRequest.visibility
  )
} catch {
  throw CommandError(
    commandStack: commandStack,
    parserError: .invalidState
  )
}

do {
    let configuration = URLSessionConfiguration.ephemeral
    configuration.requestCachePolicy = .reloadIgnoringLocalCacheData
    configuration.urlCache = nil

    let session = URLSession(configuration: configuration)

    var request = URLRequest(url: cloudhookURL)
    request.httpMethod = "HEAD"
    request.timeoutInterval = 10
    request.cachePolicy = .reloadIgnoringLocalCacheData

    let (_, response) = try await session.data(for: request)

    if let httpResponse = response as? HTTPURLResponse {
        reachabilityStatus = L10n.Settings.ConnectionSection.Cloudhook.CheckReachability
            .reachableStatusCode(httpResponse.statusCode)
    } else {
        reachabilityStatus = L10n.Settings.ConnectionSection.Cloudhook.CheckReachability.reachable
    }
} catch {
    reachabilityStatus = L10n.Settings.ConnectionSection.Cloudhook.CheckReachability
        .unreachable(error.localizedDescription)
}

switch status {
case errSecSuccess:
    guard let attributesList = result as? [[String: Any]] else {
        return []
    }

    return attributesList.compactMap { attributes in
        guard
            let serviceName = attributes[kSecAttrService as String] as? String,
            let account = attributes[kSecAttrAccount as String] as? String,
            let data = attributes[kSecValueData as String] as? Data else {
            return nil
        }

        return KeychainGenericPasswordItem(
            serviceName: serviceName,
            account: account,
            accessGroup: attributes[kSecAttrAccessGroup as String] as? String,
            accessibility: attributes[kSecAttrAccessible as String] as? String,
            data: data
        )
    }
case errSecItemNotFound:
    return []
default:
    throw KeychainExplorerError(status: status)
}

switch existentAction {
case let .navigate(path):
    viewModel.navigationPathAction = path
case let .runScript(serverId, scriptId):
    do {
        let entity = try HAAppEntity.config().first(where: { entity in
            entity.serverId == serverId && entity.entityId == scriptId
        })
        viewModel.selectedEntity = entity
    } catch {
        Current.Log
            .error("Failed to prefill script entity in magic item customization: \(error.localizedDescription)")
    }
case let .assist(serverId, pipelineId, startListening):
    viewModel.startListeningAssistAction = startListening
    viewModel.selectedPipelineId = pipelineId
    viewModel.selectedServerIdForPipeline = serverId
case .default, .nothing, .moreInfoDialog:
    break
}

switch event.eventType {
case let .region(region, state):
    guard let api = Current.api(for: server) else {
        Current.Log.error("No API available to fire ZoneManager event, server: \(server)")
        return
    }
    let eventInfo = api.zoneStateEvent(region: region, state: state, zone: zone)
    api.CreateEvent(eventType: eventInfo.eventType, eventData: eventInfo.eventData).pipe { result in
        switch result {
        case .fulfilled:
            Current.Log.info("Fired ZoneManager event")
        case let .rejected(error):
            let message = "Failed to fire ZoneManager event: \(error.localizedDescription)"
            Current.Log.error(message)
            Current.clientEventStore.addEvent(.init(text: message, type: .locationUpdate))
            Current.notificationDispatcher.send(.init(
                id: .debug,
                title: "DEBUG: Failed to fire ZoneManager",
                body: message
            ))
        }
    }
case .locationChange:
    break
}

do {
    if settings.ttsDeactivateBeforeReconfigure {
        try audioSession.setActive(false, options: .notifyOthersOnDeactivation)
    }

    try audioSession.setCategory(
        settings.ttsCategory.avCategory,
        mode: settings.ttsMode.avMode,
        options: makeAudioSessionOptions(
            allowBluetoothHFP: settings.ttsAllowBluetoothHFP,
            allowBluetoothA2DP: settings.ttsAllowBluetoothA2DP,
            duckOthers: settings.ttsDuckOthers,
            interruptSpokenAudio: settings.ttsInterruptSpokenAudio
        )
    )

    if settings.ttsActivateAudioSession {
        try audioSession.setActive(true)
    }

    logCurrentAudioRoute(context: "tts configured")
} catch {
    Current.Log.error("CarPlay Assist failed to configure TTS audio session: \(error.localizedDescription)")
}

do {
	guard let pendingArticleIDs = await syncDatabase.selectPendingStarredStatusArticleIDs() else {
		return
	}

	let feedbinStarredArticleIDs = Set(articleIDs.map { String($0) })
	let updatableFeedbinStarredArticleIDs = feedbinStarredArticleIDs.subtracting(pendingArticleIDs)

	let currentStarredArticleIDs = try await account.fetchStarredArticleIDsAsync()

	// Mark articles as starred
	let deltaStarredArticleIDs = updatableFeedbinStarredArticleIDs.subtracting(currentStarredArticleIDs)
	try await account.markAsStarredAsync(articleIDs: deltaStarredArticleIDs)

	// Mark articles as unstarred
	let deltaUnstarredArticleIDs = currentStarredArticleIDs.subtracting(updatableFeedbinStarredArticleIDs)
	try await account.markAsUnstarredAsync(articleIDs: deltaUnstarredArticleIDs)
} catch {
	Self.logger.error("Feedbin: Sync Article Starred Status failed: \(error.localizedDescription)")
	postSyncError(error, account: account, operation: "Syncing starred status")
}

do {
	return try await account.logActivity(kind: .subscribeFeed, detail: urlString) {

		let searchResponse = try await caller.getFeeds(for: urlString, count: 1, locale: Locale.current.identifier)
		guard let firstResult = searchResponse.results.first else {
			throw AccountError.createErrorNotFound
		}
		let feedResource = FeedlyFeedResourceID(id: firstResult.feedID)

		let collectionFeeds = try await caller.addFeed(with: feedResource, title: name, toCollectionWith: collectionID)
		guard collectionFeeds.contains(where: { $0.id == feedResource.id }) else {
			throw AccountError.createErrorNotFound
		}

		syncFeedsForCollectionFolders([(collectionFeeds, folder)], in: account)

		try await ingestUnreadArticleIDs(for: account, userID: credentials.username)
		try await syncStreamContents(for: account, resource: feedResource, paginated: false, newerThan: nil)

		guard let feed = folder.existingFeed(withFeedID: feedResource.id) else {
			throw AccountError.createErrorNotFound
		}
		return feed
	}
} catch {
	throw AccountError.wrapped(error, account)
}

do {
	guard let pendingStoryHashes = await syncDatabase.selectPendingReadStatusArticleIDs() else {
		return
	}

	let newsBlurUnreadStoryHashes = Set(hashes.map { $0.hash })
	let updatableNewsBlurUnreadStoryHashes = newsBlurUnreadStoryHashes.subtracting(pendingStoryHashes)

	let currentUnreadArticleIDs = try await account.fetchUnreadArticleIDsAsync()

	// Mark articles as unread
	let deltaUnreadArticleIDs = updatableNewsBlurUnreadStoryHashes.subtracting(currentUnreadArticleIDs)
	try await account.markAsUnreadAsync(articleIDs: deltaUnreadArticleIDs)

	// Mark articles as read
