do {
	return try await account.logActivity(kind: .subscribeFeed, detail: url.absoluteString) {
		let feedSpecifiers = try await FeedFinder.find(url: url)
		refreshProgress.completeTask()

		let filteredFeedSpecifiers = feedSpecifiers.filter { !$0.urlString.contains("json") }
		guard let bestFeedSpecifier = FeedSpecifier.bestFeed(in: filteredFeedSpecifiers) else {
			refreshProgress.reset()
			throw AccountError.createErrorNotFound
		}

		let subResult = try await caller.createSubscription(url: bestFeedSpecifier.urlString, name: name)
		refreshProgress.completeTask()

		switch subResult {
		case .created(let subscription):
			return try await createFeed(account: account, subscription: subscription, name: name, container: container)
		case .notFound:
			throw AccountError.createErrorNotFound
		}
	}
} catch {
	Self.logger.error("ReaderAPIAccountDelegate: createFeed - error: \(error.localizedDescription)")
	refreshProgress.reset()
	throw AccountError.createErrorNotFound
}

while resultSet.next() {

	guard let articleID = resultSet.swiftString(forColumn: DatabaseKey.articleID) else {
		assertionFailure("Expected articleID.")
		continue
	}

	if let cachedArticle = articlesCache.withLock({ $0[articleID] }) {
		articles.insert(cachedArticle)
		continue
	}

	// The resultSet is a result of a JOIN query with the statuses table,
	// so we can get the statuses at the same time and avoid additional database lookups.
	guard let status = statusesTable.statusWithRow(resultSet, articleID: articleID) else {
		assertionFailure("Expected status.")
		continue
	}

	guard let article = Article(accountID: accountID, row: resultSet, status: status) else {
		continue
	}
	articlesCache.withLock { $0[articleID] = article }
	articles.insert(article)
}

switch CloudKitZoneResult.resolve(error) {
case .success:
	if let record = record {
		captures.completion(.success(record))
	} else {
		captures.completion(.failure(CloudKitZoneError.unknown))
	}
case .zoneNotFound:
	self.createZoneRecord { result in
		switch result {
		case .success:
			self.fetch(externalID: externalID, completion: captures.completion)
		case .failure(let error):
			captures.completion(.failure(error))
		}
	}
case .retry(let timeToWait):
	Self.logger.debug("CloudKitZone: fetch \(self.zoneID.zoneName, privacy: .public) externalID: \(externalID) zone fetch retry in \(timeToWait) seconds")
	await self.delaySeconds(timeToWait)
	self.fetch(externalID: externalID, completion: captures.completion)
case .userDeletedZone:
	captures.completion(.failure(CloudKitZoneError.userDeletedZone))
default:
	captures.completion(.failure(CloudKitError(error!)))
}

while !container.isAtEnd {
  let key = try container.decode(Key.self)
  let (index, bucket) = self._keys._find(key)
  guard index == nil else {
    let context = DecodingError.Context(
      codingPath: container.codingPath,
      debugDescription: "Duplicate key at offset \(container.currentIndex - 1)")
    throw DecodingError.dataCorrupted(context)
  }

  guard !container.isAtEnd else {
    throw DecodingError.dataCorrupted(
      DecodingError.Context(
        codingPath: container.codingPath,
        debugDescription: "Unkeyed container reached end before value in key-value pair"
      )
    )
  }
  let value = try container.decode(Value.self)
  _keys._appendNew(key, in: bucket)
  _values.append(value)
}

switch retryResult {
case .doNotRetry:
    didComplete = { completionHandler(response) }

case let .doNotRetryWithError(retryError):
    let result: AFResult<Serializer.SerializedObject> = .failure(retryError.asAFError(orFailWith: "Received retryError was not already AFError"))

    let response = DataResponse(request: self.request,
                                response: self.response,
                                data: self.data,
                                metrics: self.metrics,
                                serializationDuration: end - start,
                                result: result)

    didComplete = { completionHandler(response) }

case .retry, .retryWithDelay:
    delegate.retryRequest(self, withDelay: retryResult.delay)
}

switch retryResult {
case .doNotRetry:
    didComplete = { completionHandler(response) }

case let .doNotRetryWithError(retryError):
    let result: AFResult<Serializer.SerializedObject> = .failure(retryError.asAFError(orFailWith: "Received retryError was not already AFError"))

    let response = DownloadResponse(request: self.request,
                                    response: self.response,
                                    fileURL: self.fileURL,
                                    resumeData: self.resumeData,
                                    metrics: self.metrics,
                                    serializationDuration: end - start,
                                    result: result)

    didComplete = { completionHandler(response) }

case .retry, .retryWithDelay:
    delegate.retryRequest(self, withDelay: retryResult.delay)
}

for argumentDefinition in argumentSet {
  guard case .positional = argumentDefinition.kind else { continue }
  switch argumentDefinition.parsingStrategy {
  case .default, .allRemainingInput:
    break
  default:
    continue ArgumentLoop
  }
  guard case .unary(let update) = argumentDefinition.update else {
    preconditionFailure("Shouldn't see a nullary positional argument.")
  }
  let allowOptionsAsInput =
    argumentDefinition.parsingStrategy == .allRemainingInput

  repeat {
    guard let arg = next(unconditional: allowOptionsAsInput) else {
      break ArgumentLoop
    }
    let origin: InputOrigin.Element = .argumentIndex(arg.index)
    // swift-format-ignore: NeverForceUnwrap
    // FIXME: I dont actually know why this is safe
    let value = unusedInput.originalInput(at: origin)!
    try update([origin], nil, value, &result)
    usedOrigins.insert(origin)
  } while argumentDefinition.isRepeatingPositional
}

if Current.isCatalyst {
    let query: String?
    let bundleIdentifier: String?

    switch self {
    case .location:
        bundleIdentifier = "com.apple.preference.security"
        query = "Privacy_LocationServices"
    case .motion:
        bundleIdentifier = nil
        query = nil
    case .notification, .focus:
        bundleIdentifier = "com.apple.preference.notifications"
        query = nil
    case .backgroundRefresh:
        bundleIdentifier = nil
        query = nil
    }

    if let bundleIdentifier {
        return URL(string: "x-apple.systempreferences:\(bundleIdentifier)?\(query ?? "")")!
    } else {
        return nil
    }
} else {
    return URL(string: UIApplication.openSettingsURLString)!
}

