do {
	guard let result = try await FeedParser.parse(parserData) else {
		if let activityOwner {
			ActivityLog.shared.didComplete(activityOwner, kind: activityKind, message: dataSizeMessage)
		}
		return
	}
	parsedFeed = result
} catch {
	Self.logger.error("LocalAccountRefresher: feed parse error for \(url.absoluteString): \(error.localizedDescription)")
	if let activityOwner {
		ActivityLog.shared.didFail(activityOwner, kind: activityKind, error: error)
	}
	self.feedsErrored += 1
	if let account = feed.account {
		let errorLogUserInfo = ErrorLogUserInfoKey.userInfo(sourceName: account.nameForDisplay, sourceID: account.type.rawValue, operation: "Parsing feed", errorMessage: "\(error.localizedDescription): \(url.absoluteString)")
		NotificationCenter.default.post(name: .appDidEncounterError, object: self, userInfo: errorLogUserInfo)
	}
	return
}

if level.isAtRoot, self.hasSingletonItem {
  // In this special case, the root node may turn into a collision node
  // during the merge process. Prevent this from causing issues below by
  // handling it up front.
  var copy = other
  let delta = try self.read { l in
    let lp = l.itemPtr(at: .zero)
    let c = copy.count
    let res = copy.updateValue(
      level, forKey: lp.pointee.key, _Hash(lp.pointee.key)
    ) {
      $0.initialize(to: lp.pointee)
    }
    if !res.inserted {
      try UnsafeHandle.update(res.leaf) {
        let p = $0.itemPtr(at: res.slot)
        p.pointee.value = try combine(lp.pointee.value, p.pointee.value)
      }
    }
    return c - (res.inserted ? 0 : 1)
  }
  self = copy
  return delta
}

if isSorted {
  // Already ascending: the sorted view is the input view, no copy needed.
  _applyMove(
    sourceOffsets: sourceOffsets,
    sortedSources: sourceOffsets,
    isContiguousRange: isContiguousRange,
    to: target,
    applyingTo: body)
} else {
  withUnsafeTemporaryAllocation(of: Int.self, capacity: c) { sortedBuffer in
    sortedBuffer.baseAddress!.initialize(
      from: sourceOffsets.baseAddress!, count: c)
    var sorted = sortedBuffer
    sorted.sort()
    for i in 1 ..< c {
      precondition(
        sortedBuffer[i] != sortedBuffer[i - 1],
        "Duplicate element in move list")
    }
    _applyMove(
      sourceOffsets: sourceOffsets,
      sortedSources: UnsafeBufferPointer(sortedBuffer),
      isContiguousRange: isContiguousRange,
      to: target,
      applyingTo: body)
  }
}
